package main

import "time"

// Compliant: Breaking complex expressions into readable parts
func validateUser(user *User, config *Config) bool {
    // GOOD: Break into logical components
    if user == nil {
        return false
    }

    isEligibleUser := user.Age >= 18 && user.IsActive && !user.IsBanned
    if !isEligibleUser {
        return false
    }

    hasValidRegistration := config.AllowNewUsers || isLegacyUser(user, config)
    hasValidSubscription := isActiveSubscription(user)

    return hasValidRegistration && hasValidSubscription
}

func isLegacyUser(user *User, config *Config) bool {
    // GOOD: Extract complex conditions into named functions
    return user.RegistrationDate.Before(config.CutoffDate) &&
           user.EmailVerified &&
           user.PhoneVerified
}

func isActiveSubscription(user *User) bool {
    // GOOD: Separate subscription validation logic
    switch user.Subscription {
    case "premium", "standard":
        return true
    case "trial":
        return user.TrialDaysLeft > 0
    default:
        return false
    }
}

func calculateDiscount(user *User, order *Order, promos []Promotion) float64 {
    // GOOD: Use intermediate variables and structured logic
    premiumDiscount := calculatePremiumDiscount(user, order)
    if premiumDiscount > 0 {
        return order.Total * premiumDiscount
    }

    standardDiscount := calculateStandardDiscount(user, order)
    return order.Total * standardDiscount
}

func calculatePremiumDiscount(user *User, order *Order) float64 {
    // GOOD: Focused function with clear logic
    isPremiumEligible := (user.Type == "premium" && user.YearsActive > 2) ||
                        (user.Type == "gold" && order.Total > 1000) ||
                        (user.ReferralCount > 5 && order.Items > 3)

    if isPremiumEligible {
        return 0.2
    }
    return 0
}

func calculateStandardDiscount(user *User, order *Order) float64 {
    // GOOD: Clear, step-by-step evaluation
    isSilverEligible := user.Type == "silver" || user.NewsletterSubscribed
    if isSilverEligible && order.Total > 500 {
        return 0.1
    }

    if order.Total > 100 && user.FirstTimeCustomer {
        return 0.05
    }

    return 0
}

func shouldProcess(data *Data, rules *Rules) bool {
    // GOOD: Use early returns and clear conditions
    if data.Type != "important" {
        return false
    }

    if data.Priority > 5 {
        return true
    }

    if shouldProcessAPI(data, rules) || shouldProcessBatch(data, rules) {
        return true
    }

    return false
}

func shouldProcessAPI(data *Data, rules *Rules) bool {
    // GOOD: Extracted API-specific logic
    return data.Source == "api" &&
           data.Authenticated &&
           data.Size < rules.MaxSize
}

func shouldProcessBatch(data *Data, rules *Rules) bool {
    // GOOD: Extracted batch-specific logic
    return data.Source == "batch" &&
           data.QueueTime.Before(rules.ProcessDeadline) &&
           data.RetryCount < rules.MaxRetries &&
           data.Valid
}
